import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

// Components
import Header from "./components/Header";
import Navbar from "./components/Navbar";
import Home from "./pages/Home";
import ListingPage from "./pages/ListingPage";
import BookingConfirmation from "./pages/BookingConfirmation";
import Experience from "./pages/Experience";
import Login from "./pages/Login";
import Signup from "./pages/Signup";

// Fix ListingList import (named export)
import ListingList from "./components/ListingList";

// Import ListingDetail if you want to use it
import ListingDetail from "./components/ListingDetail";

// Remove ListingCars unless you create it
// import ListingCars from "./components/ListingCars";

function App() {
  return (
    <Router>
      {/* Header and Navbar always visible */}
      <Header />
      <Navbar />

      {/* Routes to switch pages */}
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/listingpage" element={<ListingPage />} />
        <Route path="/booking" element={<BookingConfirmation />} />
        <Route path="/experience" element={<Experience />} />
        <Route path="/login" element={<Login />} />
        <Route path="/signup" element={<Signup />} />
      </Routes>

      {/* Example components rendered on all pages (optional) */}
      <ListingList />
      {/* <ListingCars /> */}
      <ListingDetail />
    </Router>
  );
}

export default App;
